```iFace/tmp/engineering.md#L1-1
package result

import "fmt"

// Result[T] 封装成功值或错误，二选一
type Result[T any] struct {
    value T
    err   error
    ok    bool
}

// Ok 创建成功的 Result
func Ok[T any](value T) Result[T] {
    return Result[T]{value: value, ok: true}
}

// Err 创建失败的 Result
func Err[T any](err error) Result[T] {
    return Result[T]{err: err, ok: false}
}

// Errf 创建带格式化消息的失败 Result
func Errf[T any](format string, args ...any) Result[T] {
    return Result[T]{err: fmt.Errorf(format, args...), ok: false}
}

// IsOk 判断是否成功
func (r Result[T]) IsOk() bool { return r.ok }

// IsErr 判断是否失败
func (r Result[T]) IsErr() bool { return !r.ok }

// Unwrap 获取成功值，失败时 panic
func (r Result[T]) Unwrap() T {
    if !r.ok {
        panic(fmt.Sprintf("called Unwrap on error Result: %v", r.err))
    }
    return r.value
}

// UnwrapOr 获取成功值，失败时返回默认值
func (r Result[T]) UnwrapOr(defaultVal T) T {
    if r.ok {
        return r.value
    }
    return defaultVal
}

// UnwrapOrElse 获取成功值，失败时调用 fn
func (r Result[T]) UnwrapOrElse(fn func(error) T) T {
    if r.ok {
        return r.value
    }
    return fn(r.err)
}

// Error 获取错误（成功时返回 nil）
func (r Result[T]) Error() error {
    if r.ok {
        return nil
    }
    return r.err
}

// Unpack 解包为 (T, error)，方便与 Go 惯例互操作
func (r Result[T]) Unpack() (T, error) {
    return r.value, r.err
}

// Map 将成功值转换（函数式操作）
func Map[T, U any](r Result[T], f func(T) U) Result[U] {
    if r.IsErr() {
        return Err[U](r.err)
    }
    return Ok(f(r.value))
}

// FlatMap（AndThen）：链式调用，成功时继续
func FlatMap[T, U any](r Result[T], f func(T) Result[U]) Result[U] {
    if r.IsErr() {
        return Err[U](r.err)
    }
    return f(r.value)
}
```

**使用示例：**

```iFace/tmp/engineering.md#L1-1
// 业务函数返回 Result
func fetchUser(id int) Result[*User] {
    if id <= 0 {
        return Errf[*User]("invalid id: %d", id)
    }
    user, err := db.GetUser(id)
    if err != nil {
        return Err[*User](err)
    }
    return Ok(user)
}

func fetchProfile(user *User) Result[*Profile] {
    profile, err := db.GetProfile(user.ID)
    if err != nil {
        return Err[*Profile](err)
    }
    return Ok(profile)
}

// 链式调用（避免多层 if err != nil）
func getDisplayName(userID int) Result[string] {
    return FlatMap(
        fetchUser(userID),
        func(user *User) Result[string] {
            return FlatMap(
                fetchProfile(user),
                func(p *Profile) Result[string] {
                    return Ok(p.DisplayName)
                },
            )
        },
    )
}

// 使用
name := getDisplayName(42).UnwrapOr("Anonymous")

// 与标准 Go 互操作
user, err := fetchUser(42).Unpack()
if err != nil { /* handle */ }
```

**适用场景：**
- 函数式编程风格的错误处理链。
- 需要明确强制调用方处理错误（不能忽略 Result）。
- 构建 Pipeline/DSL 时的类型安全组合。

**不适用场景：** Go 标准库和大多数社区库使用 `(T, error)` 惯例，混用会增加摩擦，需权衡。

