package errors

import (
    "errors"
    "fmt"
    "net/http"
)

// ── 错误类型定义 ──────────────────────────────────────────────────────────────

// Code 业务错误码
type Code int

const (
    CodeUnknown        Code = 0
    CodeNotFound       Code = 1001
    CodeUnauthorized   Code = 1002
    CodeForbidden      Code = 1003
    CodeInvalidInput   Code = 1004
    CodeConflict       Code = 1005
    CodeInternalError  Code = 5000
    CodeDatabaseError  Code = 5001
    CodeExternalError  Code = 5002
)

// AppError 应用层统一错误类型
type AppError struct {
    Code    Code   // 业务错误码
    Message string // 用户可见的错误信息
    Err     error  // 内部原始错误（不对外暴露）
    Op      string // 发生错误的操作名（如 "UserService.CreateUser"）
}

func (e *AppError) Error() string {
    if e.Op != "" {
        return fmt.Sprintf("[%d] %s: %s", e.Code, e.Op, e.Message)
    }
    return fmt.Sprintf("[%d] %s", e.Code, e.Message)
}

// Unwrap 支持 errors.Is / errors.As 链式查找
func (e *AppError) Unwrap() error { return e.Err }

// ── 构造函数 ──────────────────────────────────────────────────────────────────

func New(code Code, op, message string) *AppError {
    return &AppError{Code: code, Op: op, Message: message}
}

func Wrap(err error, code Code, op, message string) *AppError {
    return &AppError{Code: code, Op: op, Message: message, Err: err}
}

func NotFound(op, resource string, id any) *AppError {
    return &AppError{
        Code:    CodeNotFound,
        Op:      op,
        Message: fmt.Sprintf("%s with id=%v not found", resource, id),
    }
}

func InvalidInput(op, field, reason string) *AppError {
    return &AppError{
        Code:    CodeInvalidInput,
        Op:      op,
        Message: fmt.Sprintf("invalid field '%s': %s", field, reason),
    }
}

// ── 工具函数 ──────────────────────────────────────────────────────────────────

// GetCode 从错误链中提取 AppError 的 Code
func GetCode(err error) Code {
    var ae *AppError
    if errors.As(err, &ae) {
        return ae.Code
    }
    return CodeUnknown
}

// HTTPStatus 将 Code 映射到 HTTP 状态码
func HTTPStatus(code Code) int {
    switch code {
    case CodeNotFound:
        return http.StatusNotFound
    case CodeUnauthorized:
        return http.StatusUnauthorized
    case CodeForbidden:
        return http.StatusForbidden
    case CodeInvalidInput:
        return http.StatusBadRequest
    case CodeConflict:
        return http.StatusConflict
    default:
        return http.StatusInternalServerError
    }
}
