func (s *UserService) GetUser(ctx context.Context, id int) (*User, error) {
    const op = "UserService.GetUser"

    if id <= 0 {
        return nil, errors.InvalidInput(op, "id", "must be positive")
    }

    user, err := s.repo.GetUser(ctx, id)
    if err != nil {
        if errors.Is(err, sql.ErrNoRows) {
            return nil, errors.NotFound(op, "user", id)
        }
        // 包装底层错误，隐藏数据库细节
        return nil, errors.Wrap(err, errors.CodeDatabaseError, op, "failed to query user")
