// middleware/error_handler.go
type ErrorResponse struct {
    Code    int    `json:"code"`
    Message string `json:"message"`
}

func ErrorHandlerMiddleware(logger *slog.Logger) func(http.Handler) http.Handler {
    return func(next http.Handler) http.Handler {
        return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
            next.ServeHTTP(w, r)
        })
    }
}

// 在 handler 中统一错误响应
func respondError(w http.ResponseWriter, r *http.Request, err error, logger *slog.Logger) {
    code := apperrors.GetCode(err)
    httpStatus := apperrors.HTTPStatus(code)

    // 内部错误：记录完整错误链（含敏感信息）
    if httpStatus >= 500 {
        logger.ErrorContext(r.Context(), "internal error",
            "error", err,
            "path", r.URL.Path,
            "method", r.Method,
        )
    }

    // 对外：只返回用户友好的错误信息
    var ae *apperrors.AppError
    resp := ErrorResponse{Code: int(code)}
    if errors.As(err, &ae) {
        resp.Message = ae.Message
    } else {
        resp.Message = "internal server error"
    }

    w.Header().Set("Content-Type", "application/json")
    w.WriteHeader(httpStatus)
    json.NewEncoder(w).Encode(resp)
}
