```iFace/tmp/engineering.md#L1-1
// analyzer/errcheck/errcheck.go
package errcheck

import (
    "go/ast"
    "go/types"

    "golang.org/x/tools/go/analysis"
    "golang.org/x/tools/go/analysis/passes/inspect"
    "golang.org/x/tools/go/ast/inspector"
)

// Analyzer 是可被 golangci-lint 或 go vet 加载的分析 Pass
var Analyzer = &analysis.Analyzer{
    Name:     "customerrcheck",
    Doc:      "checks that error return values are handled",
    Run:      run,
    Requires: []*analysis.Analyzer{inspect.Analyzer},
}

func run(pass *analysis.Pass) (interface{}, error) {
    // 从依赖的 inspect Pass 获取 AST 遍历器
    insp := pass.ResultOf[inspect.Analyzer].(*inspector.Inspector)

    // 只遍历表达式语句节点（ExprStmt 是调用函数但不使用返回值的情况）
    nodeFilter := []ast.Node{
        (*ast.ExprStmt)(nil),
    }

    insp.Preorder(nodeFilter, func(n ast.Node) {
        exprStmt, ok := n.(*ast.ExprStmt)
        if !ok {
            return
        }

        // 只关心函数调用
        call, ok := exprStmt.X.(*ast.CallExpr)
        if !ok {
            return
        }

        // 获取函数调用的类型信息
        sig, ok := pass.TypesInfo.TypeOf(call).(*types.Tuple)
        _ = sig

        // 获取函数签名
        callType := pass.TypesInfo.TypeOf(call)
        if callType == nil {
            return
        }

        // 检查返回值中是否包含 error 类型
        if returnsError(pass, call) {
            pass.Reportf(call.Pos(), "return value of type error is not handled")
        }
    })

    return nil, nil
}

// returnsError 检查函数调用是否有 error 类型的返回值
func returnsError(pass *analysis.Pass, call *ast.CallExpr) bool {
    // 获取被调用函数的签名
    fn, ok := pass.TypesInfo.TypeOf(call.Fun).(*types.Signature)
    if !ok {
        return false
    }

    results := fn.Results()
    for i := 0; i < results.Len(); i++ {
        if isErrorType(results.At(i).Type()) {
            return true
        }
    }
    return false
}

// isErrorType 判断类型是否是 error 接口
func isErrorType(t types.Type) bool {
    errorType := types.Universe.Lookup("error").Type()
    return types.Identical(t, errorType) ||
        types.Implements(t, errorType.Underlying().(*types.Interface))
}
